package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertSame;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;
  private Excluder mockExcluder;

  @BeforeEach
  public void setUp() throws Exception {
    gsonBuilder = new GsonBuilder();
    mockExcluder = mock(Excluder.class);
    // Use reflection to set private field excluder to mockExcluder
    Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    excluderField.set(gsonBuilder, mockExcluder);
  }

  @Test
  public void testDisableInnerClassSerialization_returnsSameBuilderAndUpdatesExcluder() throws Exception {
    Excluder returnedExcluder = mock(Excluder.class);
    when(mockExcluder.disableInnerClassSerialization()).thenReturn(returnedExcluder);

    GsonBuilder returnedBuilder = gsonBuilder.disableInnerClassSerialization();

    // Verify the returned builder is the same instance
    assertSame(gsonBuilder, returnedBuilder);

    // Verify the excluder field is updated to returnedExcluder
    Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    Excluder actualExcluder = (Excluder) excluderField.get(gsonBuilder);
    assertSame(returnedExcluder, actualExcluder);
  }
}
